#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, B, N;
        scanf("%lld %lld %lld", &A, &B, &N);
        long long mod = 1000000007;
        long long f1 = A % mod;
        long long f2 = B % mod;
        for (int i = 3; i <= N; i++) {
            long long f3 = (f2 - f1 + mod) % mod;
            f1 = f2;
            f2 = f3;
        }
        printf("%lld\n", f2);
    }
    return 0;
}

